<script setup>
import{Head,Link,useForm}from'@inertiajs/vue3';import{computed}from'vue';import DriverLayout from'@/Layouts/DriverLayout.vue';defineOptions({layout:DriverLayout});const props=defineProps({planning:Object,roadSheet:Object});const d=v=>v?String(v).slice(0,10):'';const form=useForm({pre_service_km:props.roadSheet.pre_service_km||0,pre_service_origin:props.roadSheet.pre_service_origin||'',pre_service_note:props.roadSheet.pre_service_note||'',notes:props.roadSheet.notes||'',lines:(props.roadSheet.lines||[]).map(l=>({date:d(l.date),departure_kms:l.departure_kms??'',arrival_kms:l.arrival_kms??'',gasoline:l.gasoline??'',jawaz:l.jawaz??'',other_expenses:l.other_expenses??'',notes:l.notes||''}))});
const distance=l=>Math.max(0,Number(l.arrival_kms||0)-Number(l.departure_kms||0));const circuit=computed(()=>form.lines.reduce((s,l)=>s+distance(l),0));const total=computed(()=>circuit.value+Number(form.pre_service_km||0));const gasoline=computed(()=>form.lines.reduce((s,l)=>s+Number(l.gasoline||0),0));const jawaz=computed(()=>form.lines.reduce((s,l)=>s+Number(l.jawaz||0),0));const expenses=computed(()=>form.lines.reduce((s,l)=>s+Number(l.gasoline||0)+Number(l.jawaz||0)+Number(l.other_expenses||0),0));const clients=(props.planning.planning_clients||[]).map(x=>x.client?.full_name).filter(Boolean);const save=()=>form.put(route('driver.road-sheets.update',props.planning.id),{preserveScroll:true});
</script>
<template><Head :title="`Fiche ${planning.ref_dossier||''}`"/><div class="intro"><div class="intro-icon"><span class="material-icons-outlined">edit_note</span></div><div><strong>{{planning.ref_dossier||'Planning'}}</strong><small>{{planning.service?.designation||'Fiche de route'}}</small></div><span class="status">{{roadSheet.status_label||'À compléter'}}</span></div>
<section class="summary"><div><small>{{clients.length>1?'Clients':'Client'}}</small><strong v-for="name in clients" :key="name">{{name}}</strong><strong v-if="!clients.length">Client non renseigné</strong></div><div><small>Dates</small><strong>{{d(planning.date_du)}} → {{d(planning.date_au)}}</strong></div><div><small>Trajet</small><strong>{{planning.point_depart||'--'}} → {{planning.destination?.city||planning.destination?.name||'--'}}</strong></div><div><small>Passagers</small><strong>{{planning.nbr_personnes||0}}</strong></div></section>
<section class="card"><h2>Avant service</h2><div class="form-grid"><label>Lieu initial<input v-model="form.pre_service_origin" placeholder="Ex. Marrakech"/></label><label>Kilométrage<input v-model.number="form.pre_service_km" type="number" min="0" max="10000"/></label><label class="wide">Note<input v-model="form.pre_service_note" maxlength="500" placeholder="Facultatif"/></label></div></section>
<section class="totals"><div class="violet"><span class="material-icons-outlined">speed</span><b>{{Number(form.pre_service_km||0)}} km</b><small>Avant service</small></div><div class="blue"><span class="material-icons-outlined">route</span><b>{{circuit}} km</b><small>Circuit</small></div><div class="green"><span class="material-icons-outlined">explore</span><b>{{total}} km</b><small>Distance totale</small></div><div class="orange"><span class="material-icons-outlined">local_gas_station</span><b>{{gasoline.toFixed(2)}}</b><small>Carburant</small></div><div class="cyan"><span class="material-icons-outlined">toll</span><b>{{jawaz.toFixed(2)}}</b><small>Jawaz</small></div><div class="red"><span class="material-icons-outlined">payments</span><b>{{expenses.toFixed(2)}}</b><small>Dépenses</small></div></section>
<section class="card days"><div class="section-head"><h2>Journées du circuit</h2><span>{{form.lines.length}} jour(s)</span></div><details v-for="(line,index) in form.lines" :key="line.date" :open="index===0"><summary><div><b>Jour {{index+1}}</b><small>{{line.date}}</small></div><strong>{{distance(line)}} km</strong></summary><div class="day-grid"><label>Date<input v-model="line.date" type="date"/></label><label>Km départ<input v-model.number="line.departure_kms" type="number" min="0"/></label><label>Km arrivée<input v-model.number="line.arrival_kms" type="number" min="0"/></label><div class="distance"><small>Distance</small><b>{{distance(line)}} km</b></div><label>Carburant<input v-model.number="line.gasoline" type="number" min="0" step="0.01"/></label><label>Jawaz<input v-model.number="line.jawaz" type="number" min="0" step="0.01"/></label><label>Autres dépenses<input v-model.number="line.other_expenses" type="number" min="0" step="0.01"/></label><label>Notes<input v-model="line.notes" maxlength="255"/></label></div></details><label class="general">Notes générales<textarea v-model="form.notes" rows="2"></textarea></label></section>
<div v-if="Object.keys(form.errors).length" class="errors">Vérifiez les champs indiqués. Les kilomètres doivent être positifs et les dates uniques.</div><div class="actions"><Link :href="route('driver.road-sheets.index')">Annuler</Link><button :disabled="form.processing" @click="save"><span class="material-icons-outlined">save</span>{{form.processing?'Enregistrement...':'Enregistrer la fiche'}}</button></div>
</template>
<style scoped>.intro{min-height:64px;padding:10px 12px;border:1px solid #e2e8f0;border-radius:18px;background:#fff;display:flex;align-items:center;gap:10px}.intro-icon{width:40px;height:40px;border-radius:13px;background:#fee2e2;color:#dc2626;display:grid;place-items:center}.intro>div:nth-child(2){flex:1}.intro strong,.intro small{display:block}.intro small{margin-top:2px;color:#64748b;font-size:10px}.status{padding:6px 9px;border-radius:99px;background:#fef3c7;color:#b45309;font-size:9px;font-weight:900}.summary{margin:9px 0;display:grid;grid-template-columns:repeat(4,1fr);gap:6px}.summary>div{padding:9px;border:1px solid #e2e8f0;border-radius:13px;background:#fff}.summary small,.summary strong{display:block}.summary small{color:#64748b;font-size:9px;font-weight:900;text-transform:uppercase}.summary strong{margin-top:3px;color:#0f172a;font-size:11px;overflow-wrap:anywhere}.card{margin-bottom:9px;padding:11px;border:1px solid #e2e8f0;border-radius:17px;background:#fff}.card h2{margin:0;font-size:14px}.form-grid{display:grid;grid-template-columns:1fr 1fr;gap:7px}.wide{grid-column:1/-1}label{color:#334155;font-size:10px;font-weight:900}input,textarea{display:block;width:100%;margin-top:4px;border:1px solid #e2e8f0;border-radius:11px;background:#f8fafc;color:#0f172a;padding:0 10px;font-weight:700}input{height:38px}textarea{padding-top:8px;resize:vertical}.totals{margin-bottom:9px;display:grid;grid-template-columns:repeat(3,1fr);gap:6px}.totals>div{min-height:70px;padding:8px;border:1px solid #e2e8f0;border-top:3px solid var(--tone);border-radius:15px;background:#fff;display:grid;grid-template-columns:28px 1fr;align-items:center;column-gap:7px}.totals span{width:28px;height:28px;border-radius:9px;background:var(--soft);color:var(--tone);display:grid;place-items:center;font-size:15px}.totals b{font-size:15px}.totals small{grid-column:1/-1;color:#64748b;font-size:9px;font-weight:800}.violet{--tone:#7c3aed;--soft:#ede9fe}.blue{--tone:#2563eb;--soft:#dbeafe}.green{--tone:#16a34a;--soft:#dcfce7}.orange{--tone:#f59e0b;--soft:#fef3c7}.cyan{--tone:#0891b2;--soft:#cffafe}.red{--tone:#dc2626;--soft:#fee2e2}.section-head{display:flex;align-items:center;justify-content:space-between}.section-head span{color:#64748b;font-size:10px;font-weight:900}details{margin-top:7px;border:1px solid #e2e8f0;border-radius:13px;background:#f8fafc;overflow:hidden}summary{padding:9px 10px;cursor:pointer;display:flex;align-items:center;justify-content:space-between}summary small,summary b{display:block}summary small{color:#64748b;font-size:9px}summary strong{color:#dc2626;font-size:11px}.day-grid{padding:0 9px 9px;display:grid;grid-template-columns:repeat(4,1fr);gap:7px}.distance{align-self:end;height:38px;padding:5px 9px;border-radius:10px;background:#fee2e2;display:flex;align-items:center;justify-content:space-between;color:#991b1b}.distance small{font-size:9px}.general{display:block;margin-top:8px}.actions{position:sticky;bottom:8px;padding:8px;border:1px solid #e2e8f0;border-radius:16px;background:#ffffffee;box-shadow:0 8px 25px #0f172a18;display:flex;justify-content:flex-end;gap:8px}.actions a,.actions button{height:42px;padding:0 16px;border:0;border-radius:12px;display:flex;align-items:center;gap:6px;text-decoration:none;font-size:11px;font-weight:900}.actions a{background:#f1f5f9;color:#64748b}.actions button{background:#dc2626;color:#fff}.errors{margin-bottom:8px;padding:10px;border-radius:12px;background:#fef2f2;color:#b91c1c;font-size:11px;font-weight:800}@media(max-width:900px){.summary{grid-template-columns:repeat(2,1fr)}.day-grid{grid-template-columns:repeat(2,1fr)}}@media(max-width:560px){.totals{grid-template-columns:repeat(2,1fr)}.form-grid{grid-template-columns:1fr}.wide{grid-column:auto}.day-grid{grid-template-columns:1fr 1fr}.intro{border-radius:15px}.status{display:none}.actions{bottom:4px}.actions a,.actions button{flex:1;justify-content:center;padding:0 8px}}</style>
